#!/usr/bin/env node
const fs=require("fs"),path=require("path");console.log("🔍 Notification Check Script"),console.log("=".repeat(50)),console.log("🤖 1. Bot Status Check:");const{exec:exec}=require("child_process");function checkLogs(){if(console.log("\n📋 2. Log File Check:"),fs.existsSync("bot.log")){console.log("✅ bot.log exists");const stats=fs.statSync("bot.log"),fileSize=(stats.size/1024).toFixed(2);console.log(`   Size: ${fileSize} KB`),console.log(`   Last modified: ${stats.mtime}`);const lastLines=fs.readFileSync("bot.log","utf8").split("\n").slice(-20).filter((line=>line.trim()));console.log("\n📝 Last 20 log lines:"),lastLines.forEach((line=>{console.log(`   ${line}`)}))}else console.log("❌ bot.log not found"),console.log("💡 Bot might not be logging to file");["nft-tracker.log","discord.log","error.log"].forEach((logFile=>{fs.existsSync(logFile)&&console.log(`✅ ${logFile} exists`)})),checkEnvironment()}function checkEnvironment(){if(console.log("\n🌍 3. Environment Check:"),fs.existsSync(".env")){console.log("✅ .env file exists");const lines=fs.readFileSync(".env","utf8").split("\n");console.log("   Environment variables:"),lines.forEach((line=>{if(line.trim()&&!line.startsWith("#")){const[key]=line.split("=");if(key){const value=process.env[key];value?console.log(`     ${key}: ${value.substring(0,10)}...`):console.log(`     ${key}: ❌ Not set`)}}}))}else console.log("❌ .env file not found"),console.log("💡 Create .env file with your Discord credentials");try{const config=require("./config");console.log("\n📋 4. Config Check:"),console.log("   Discord Bot Token: "+(config.discord.botToken?"✅ Set":"❌ Missing")),console.log("   Discord Channel ID: "+(config.discord.channelId?"✅ Set":"❌ Missing")),console.log("   OpenSea API Key: "+(config.opensea.apiKey?"✅ Set":"❌ Missing")),console.log("   Etherscan API Key: "+(config.etherscan.apiKey?"✅ Set":"❌ Missing"))}catch(error){console.log("❌ Error reading config:",error.message)}checkWallets()}function checkWallets(){if(console.log("\n👥 5. Wallets Check:"),fs.existsSync("wallets.csv")){const lines=fs.readFileSync("wallets.csv","utf8").trim().split("\n"),walletCount=lines.length-1;console.log(`✅ Found ${walletCount} wallets in wallets.csv`),walletCount>0&&(console.log("   Sample wallets:"),lines.slice(1,4).forEach((line=>{const[address,name]=line.split(",");console.log(`     ${name}: ${address.substring(0,10)}...`)})),walletCount>3&&console.log(`     ... and ${walletCount-3} more`))}else console.log("❌ wallets.csv not found");checkRecentActivity()}function checkRecentActivity(){if(console.log("\n📊 6. Recent Activity Check:"),fs.existsSync("data")){console.log("✅ data/ directory exists");const dataFiles=fs.readdirSync("data");dataFiles.length>0&&(console.log("   Data files:"),dataFiles.forEach((file=>{const filePath=path.join("data",file),stats=fs.statSync(filePath),fileSize=(stats.size/1024).toFixed(2);console.log(`     ${file}: ${fileSize} KB, modified: ${stats.mtime}`)})))}else console.log("❌ data/ directory not found");if(fs.existsSync("data/purchases.json"))try{const purchases=JSON.parse(fs.readFileSync("data/purchases.json","utf8")),purchaseCount=Object.keys(purchases).length;console.log(`   Purchase records: ${purchaseCount}`)}catch(error){console.log("   ❌ Error reading purchases.json:",error.message)}console.log("\n"+"=".repeat(50)),console.log("🎯 Notification check complete!"),console.log("\n💡 Next steps:"),console.log("   1. Run: node debug-discord.js"),console.log("   2. Check bot logs: tail -f bot.log"),console.log("   3. Verify Discord bot permissions"),console.log("   4. Test with: node test-discord-connection.js")}exec('ps aux | grep "node index.js" | grep -v grep',((error,stdout,stderr)=>{if(!stdout)return console.log("❌ Bot is not running"),void console.log("💡 Start the bot with: node index.js");console.log("✅ Bot is running");stdout.trim().split("\n").forEach((line=>{const parts=line.split(/\s+/),pid=parts[1],cpu=parts[2],mem=parts[3];console.log(`   PID: ${pid}, CPU: ${cpu}%, Memory: ${mem}%`)}));checkLogs()}));